#!/bin/sh
# Build each mozaic benchmark for BOTH backends (CPU and Metal) and compare ns/launch.
# Everything measured here is generated by the mozaic compiler — kernel, launch, runtime.
set -e
here=$(cd "$(dirname "$0")" && pwd)
root=$(cd "$here/.." && pwd)
comp="node --disable-warning=ExperimentalWarning $root/src/main.ts"

row() {
  name=$1; file=$2
  cpu=$($comp run "$file"        2>/dev/null | head -1)
  gpu=$($comp run "$file" --gpu  2>/dev/null | head -1)
  awk -v n="$name" -v c="$cpu" -v g="$gpu" 'BEGIN {
    printf "%-7s | CPU %12.3f us | GPU %12.3f us | %8.1fx\n", n, c/1000.0, g/1000.0, c/g
  }'
}

echo "mozaic-compiled kernels — microseconds per launch (lower = faster)"
echo "kernel  |       CPU (serial) |        GPU (Metal) | speedup"
echo "--------+--------------------+--------------------+--------"
row heavy "$here/heavy.mzc"
row vadd  "$here/vadd.mzc"